import { db } from "@/lib/db";
import { decryptObject } from "@/lib/crypto";
import { obfuscateLua } from "@/lib/obfuscator";
import { getClientIp } from "@/lib/http";

function escapeLuaString(s: string): string {
  return s.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\n/g, "\\n").replace(/\r/g, "\\r");
}

function isBrowserRequest(req: Request): boolean {
  const accept = req.headers.get("accept") || "";
  const secFetchMode = req.headers.get("sec-fetch-mode") || "";
  const secFetchSite = req.headers.get("sec-fetch-site") || "";
  if (secFetchMode === "navigate" || secFetchSite === "none" || secFetchSite === "cross-site") return true;
  if (accept.includes("text/html") && accept.includes("application/xhtml")) return true;
  return false;
}

export async function GET(req: Request, { params }: { params: Promise<{ scriptId: string }> }) {
  const { scriptId } = await params;
  const url = new URL(req.url);
  const uiMode = url.searchParams.get("ui");
  const ip = getClientIp(req);

  const script = await db.script.findUnique({
    where: { id: scriptId },
    select: { id, name, status, visibility, contentEncrypted, version, ownerId, getKeyLink, keyMode },
  }).catch(() => null);

  // Not-found: returns HTML page for browsers, plain text "ERROR: Script not found" for executors
  // Browser requests are BLOCKED with an HTML "Unauthorized Access" page (only executors get Lua)
  // Logs access to scriptAccessLog (LOADER_FETCH)
  // Builds Lua with baseUrl/_AUTH/_SID constants

  // Lua includes:
  //   - Anti-env-logger checks: verifies Players.LocalPlayer.UserId>=1, Character exists,
  //     RunService IsStudio/IsClient, Workspace:GetDescendants(), TextChatService — returns if mock env
  //   - rawget(getfenv(),"loadstring") to avoid hooks; game.HttpGet stored in _rhttp
  //   - _hw() collects HWID via gethwid/syn/fluxus/evon/krnl .get_hwid (fallback "unknown"..os.clock())
  //   - _exn() executor name via getexecutorname/identifyexecutor
  //   - _enc() URL-encodes a string; _sk/_lk/_ck save/load/clear "FireLabKey.txt"
  //   - _k() kicks player + infinite loop
  //
  // Three branches based on script.keyMode/visibility:
  //   showKeyPrompt (normal): _kp() builds full animated ScreenGui key prompt, calls _AUTH with key,
  //     loads returned payload via loadstring, persists key to FireLabKey.txt. NOTE: contains a syntax
  //     error — `local _tok=string.match(_vbody or _cbody, --FL:(.-)$")` has an unmatched quote/paren.
  //   isKeyless (PUBLIC): immediate HttpGet with key="KEYLESS", then task.spawn heartbeat every 60s
  //     re-checking auth (&check=1)
  //   isPremium: reads script_key global or FireLabKey.txt, calls _AUTH, heartbeat re-check every 60s
  //   default (normal): shows _kp() key prompt UI, waits up to 600s, calls _AUTH, heartbeat re-check

  const obfuscatedLoader = obfuscateLua(lua, { strength: "maximum" });
  return new NextResponse(obfuscatedLoader, {
    headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store, no-cache, must-revalidate", "Access-Control-Allow-Origin": "*" },
  });
}
```
