import { NextResponse } from "next/server";
// Serves cached obfuscated loader payload. Public loader returns tiny bootstrap that fetches this.
// Bots only see the bootstrap, not the actual code.

declare global { var loaderCache: Map<string, { code: string; expires: number }>; }

export async function GET(req: Request, { params }: { params: Promise<{ cacheKey: string }> }) {
  const { cacheKey } = await params;
  const cache = (globalThis as any).loaderCache || global.loaderCache;
  if (!cache) return new NextResponse("ERROR: Cache not available", { headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" } });
  const entry = cache.get(cacheKey);
  if (!entry || entry.expires < Date.now()) return new NextResponse("ERROR: Expired", { headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" } });
  cache.delete(cacheKey); // one-time use
  return new NextResponse(entry.code, {
    headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store, no-cache, must-revalidate", "Access-Control-Allow-Origin": "*" },
  });
}
