import { NextResponse } from "next/server";
import { obfuscateLua } from "@/lib/obfuscator";
import { getAuthenticatedUser, rateLimit } from "@/lib/http";
import { z } from "zod";

const schema = z.object({
  source: z.string().min(1).max(5_000_000),
  strength: z.enum(["standard", "strong", "maximum"]).optional().default("strong"),
});

export async function POST(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const limited = await rateLimit(`obfuscate:${user.id}`, 20, 60 * 1000);
  if (!limited.success) return NextResponse.json({ error: "Too many requests" }, { status: 429 });
  try {
    const body = schema.safeParse(await req.json());
    if (!body.success) return NextResponse.json({ error: "Invalid input" }, { status: 400 });
    const output = obfuscateLua(body.data.source, { strength: body.data.strength });
    return NextResponse.json({ output });
  } catch (error) {
    console.error("Obfuscate error:", error);
    return NextResponse.json({ error: "Obfuscation failed" }, { status: 500 });
  }
}
