import { randomBytes } from "crypto";

type Strength = "standard" | "strong" | "maximum";
type ObfuscateOptions = { strength?: Strength; [key: string]: any; };

export function isLoadStringPayload(source: string) {
  return source.includes("FireLabPayload") && !source.includes("game:HttpGet") && !source.includes("ScreenGui");
}

function stripComments(source: string): string {
  let res = "", ci = 0;
  let inStr = false, strCh = "";
  while (ci < source.length) {
    const ch = source[ci]; const nx = source[ci + 1];
    if (inStr) {
      if (ch === "\\" && nx !== undefined) { res += ch + nx; ci += 2; continue; }
      if (ch === strCh) inStr = false;
      res += ch; ci++; continue;
    }
    if (ch === '"' || ch === "'") { inStr = true; strCh = ch; res += ch; ci++; continue; }
    if (ch === "-" && nx === "-" && source[ci + 2] === "[" && source[ci + 3] === "[") {
      ci += 4;
      while (ci < source.length) { if (source[ci] === "]" && source[ci + 1] === "]") { ci += 2; break; } ci++; }
      continue;
    }
    if (ch === "-" && nx === "-") { while (ci < source.length && source[ci] !== "\n") ci++; continue; }
    res += ch; ci++;
  }
  return res.trim();
}

function deriveKeyByte(seed: number, index: number): number {
  let v = seed;
  v = (v * 1103515245 + 12345 + index * 7919) % 2147483647;
  const hi = Math.floor(v / 65536) % 256;
  const lo = v % 256;
  let a = hi, b = lo, result = 0, bv = 1;
  while (a > 0 || b > 0) {
    if ((a % 2) !== (b % 2)) result += bv;
    a = Math.floor(a / 2); b = Math.floor(b / 2); bv *= 2;
  }
  return result % 256;
}

export function obfuscateLua(source: string, options: ObfuscateOptions = {}): string {
  if (!source.trim()) return source;
  if (isLoadStringPayload(source)) return source;
  source = stripComments(source);
  const strength = options.strength ?? "strong";
  const keyLength = strength === "maximum" ? 32 : strength === "strong" ? 24 : 16;
  const seed = parseInt(randomBytes(4).toString("hex"), 16);
  const saltSeed = parseInt(randomBytes(4).toString("hex"), 16);
  const rawKey: number[] = [];
  for (let i = 0; i < keyLength; i++) rawKey.push(deriveKeyByte(seed, i));
  const saltKey: number[] = [];
  for (let i = 0; i < keyLength; i++) saltKey.push(deriveKeyByte(saltSeed, i));
  const rotation = Math.floor(seed / 256) % 256;
  const posKey = Math.floor(saltSeed / 65536) % 256;
  const sourceBytes = Array.from(Buffer.from(source, "utf8"));

  function mxor(a: number, b: number): number {
    let r = 0, bv = 1;
    while (a > 0 || b > 0) { if ((a % 2) !== (b % 2)) r += bv; a = Math.floor(a / 2); b = Math.floor(b / 2); bv *= 2; }
    return r;
  }

  const encrypted = sourceBytes.map((byte, i) => {
    let b = mxor(byte, rawKey[i % rawKey.length]) % 256;
    b = mxor(b, saltKey[i % saltKey.length]) % 256;
    b = (b + rotation) % 256;
    b = mxor(b, (posKey + i) % 256) % 256;
    return b;
  });

  const dataTable = `{${encrypted.join(",")}}`;

  const lua = `local t=${dataTable} local a=${seed} local b=${saltSeed} local c=#t local function xr(p,q) local r=0 local bv=1 while p>0 or q>0 do local pb=p%2 local qb=q%2 if pb~=qb then r=r+bv end p=math.floor(p/2) q=math.floor(q/2) bv=bv*2 end return r end local function dk(s,i) local v=s v=(v*1103515245+12345+i*7919)%2147483647 local hi=math.floor(v/65536)%256 local lo=v%256 return xr(hi,lo)%256 end local k={} for i=1,c do k[i]=xr(dk(a,i-1),dk(b,i-1)) end local r=math.floor(a/256)%256 local p=math.floor(b/65536)%256 local s2={} for i=1,c do s2[i]=dk(b,i-1) end local w={} local i=1 while i<=c do local v=t[i] v=xr(v%256,(p+i-1)%256)%256 v=(v-r)%256 v=xr(v%256,s2[i])%256 v=xr(v%256,k[i])%256 w[i]=string.char(v%256) i=i+1 end local m=table.concat(w) local g=loadstring or load local fn=g(m,"FireLabPayload") if not fn then error("E4") end t=nil m=nil w=nil k=nil s2=nil collectgarbage("collect") collectgarbage("collect") local ok2,err=pcall(fn) fn=nil g=nil collectgarbage("collect") if not ok2 then error(err or "E5") end`;

  return lua;
}

export function obfuscateLuaToLoadString(source: string, options: ObfuscateOptions = {}): string {
  return obfuscateLua(source, options);
}
```
**OBSERVATIONS:** Custom XOR-rotation cipher with key derived from two 32-bit seeds embedded IN PLAINTEXT in the output (`local a=<seed> local b=<saltSeed>`). The full key-derivation algorithm ships with every payload, so it is trivially reversible — this is obfuscation, not encryption. `isLoadStringPayload` short-circuits re-obfuscation. Output uses `loadstring`/`load` with chunk name "FireLabPayload". Encryption uses math-based XOR (not `^`) to mirror Lua exactly. `(v-r)%256` in decoder can produce negative-ish behavior in Lua but `%256` keeps it in range.

