    data: { lastUsedAt: new Date() },
  });

  if (!apiToken.user || apiToken.user.banned) return null;
  return apiToken.user;
}

export async function getJson<T>(req: Request): Promise<T> {
  try {
    return (await req.json()) as T;
  } catch {
    throw new Error("Invalid JSON body");
  }
}

export function getClientIp(req: Request): string {
  const forwarded = req.headers.get("x-forwarded-for");
  if (forwarded) {
    return forwarded.split(",")[0]?.trim() || "unknown";
  }
  return req.headers.get("x-real-ip") || "unknown";
}

export function isUnsafeMethod(method: string) {
  return !["GET", "HEAD", "OPTIONS", "TRACE"].includes(method);
}

export function verifyCsrf(req: Request): boolean {
  if (!isUnsafeMethod(req.method)) return true;
  if (process.env.NODE_ENV !== "production") return true;

  const origin = req.headers.get("origin");
  const host = req.headers.get("host");
  const referer = req.headers.get("referer");

  if (origin) {
    try {
      return isAllowedHost(new URL(origin).host) && isAllowedHost(host);
    } catch {
      return false;
    }
  }

  if (referer) {
    try {
      return isAllowedHost(new URL(referer).host) && isAllowedHost(host);
    } catch {
      return false;
    }
  }

  return true;
}

export async function getAuthenticatedUser(
  req?: Request,
): Promise<SessionUser | null> {
  const cookieStore = await cookies();
  let token = getCookieValue(req, "token") || cookieStore.get("token")?.value;

  if (!token && req?.headers.get("authorization")?.startsWith("Bearer ")) {
    token = req.headers.get("authorization")!.substring(7);
  }

  if (!token) return null;

  const apiTokenUser = await getUserFromApiToken(token);
  if (apiTokenUser) return apiTokenUser;

  const decoded = verifyToken(token);
  if (!decoded) return null;

  const session = await db.session.findUnique({
    where: { sessionToken: token },
    select: { expiresAt: true, revokedAt: true, userId: true },
  });

  if (
    !session ||
    session.revokedAt ||
    session.expiresAt < new Date() ||
    session.userId !== decoded.userId
  ) {
    await db.session
      .deleteMany({
        where: {
          sessionToken: token,
          OR: [{ expiresAt: { lt: new Date() } }, { revokedAt: { not: null } }],
        },
      })
      .catch(() => undefined);
    return null;
  }

  await db.session.updateMany({
    where: { sessionToken: token },
    data: { lastUsedAt: new Date() },
  });

  const user = await db.user.findUnique({
    where: { id: decoded.userId },
    select: {
      id: true,
      username: true,
      email: true,
      role: true,
      discordId: true,
      githubId: true,
      avatarUrl: true,
      displayName: true,
      twoFactorEnabled: true,
      isVerified: true,
      banned: true,
    },
  });

  if (!user || user.banned) return null;
  return user;
}

export function setAuthCookie(response: NextResponse, token: string) {
  response.cookies.set("token", token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 60 * 60 * 24 * 7,
    path: "/",
  });
}

export function clearAuthCookie(response: NextResponse) {
  response.cookies.set("token", "", {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 0,
    path: "/",
  });
}

export function hashIdentifier(identifier: string): string {
  return hashString(identifier);
}

export function getRateLimitHeaders(result: {
  limit: number;
  remaining: number;
  reset: number;
}) {
  return {
    "X-RateLimit-Limit": result.limit.toString(),
    "X-RateLimit-Remaining": result.remaining.toString(),
    "X-RateLimit-Reset": Math.ceil(result.reset / 1000).toString(),
  };
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { rateLimit } from "@/lib/rate-limit";
import { getRateLimitHeaders } from "@/lib/rate-limit";
import { decryptObject, hashString, hashToken, randomToken } from "@/lib/crypto";
import { obfuscateLua, isLoadStringPayload } from "@/lib/obfuscator";
import { getClientIp, hashIdentifier } from "@/lib/http";
import { recordSecurityFailure } from "@/lib/ip-reputation";
import { sendDiscordLog } from "@/lib/discord-logger";

// In-memory stores (cleared on restart)
const sessionTokens = new Map<string, { keyHash: string; ip: string; hwid: string; expires: number }>();
const keyAttempts = new Map<string, { count: number; firstAttempt: number }>();
const recentNonces = new Map<string, number>();
const activeSessions = new Map<string, string>(); // keyHash -> sessionId

function errorResponse(message: string, status = 401) {
  return new NextResponse(`ERROR: ${message}`, {
    status,
    headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" },
  });
}

function parseQuery(url: URL) {
  return {
    key: url.searchParams.get("key") || "",
    hwid: url.searchParams.get("hwid") || "",
    scriptId: url.searchParams.get("scriptId") || "",
    nonce: url.searchParams.get("nonce") || "",
    timestamp: url.searchParams.get("ts") ? Number(url.searchParams.get("ts")) : undefined,
    executor: url.searchParams.get("executor") || "Unknown",
    token: url.searchParams.get("token") || "",
    check: url.searchParams.get("check") === "1",
  };
}

function getSafeIp(req: Request): string {
  // Only trust the FIRST IP in X-Forwarded-For (closest proxy)
  // Railway sets this correctly — don't trust client-supplied spoofing
  const xff = req.headers.get("x-forwarded-for") || "";
  const first = xff.split(",")[0]?.trim();
  if (first && /^\d+\.\d+\.\d+\.\d+$/.test(first)) return first;
  return req.headers.get("x-real-ip") || "unknown";
}

function cleanExpiredStores() {
  const now = Date.now();
  // Session tokens expire after 5 minutes
  for (const [token, data] of sessionTokens) {
    if (data.expires < now) sessionTokens.delete(token);
  }
  // Key attempts reset after 1 hour
  for (const [key, data] of keyAttempts) {
    if (now - data.firstAttempt > 3600000) keyAttempts.delete(key);
  }
  // Nonces expire after 5 minutes
  for (const [nonce, expires] of recentNonces) {
    if (expires < now) recentNonces.delete(nonce);
  }
  // Active sessions expire after 2 minutes (if no runtime check)
  for (const [keyHash, sessionId] of activeSessions) {
    const session = sessionTokens.get(sessionId);
    if (!session || session.expires < now) activeSessions.delete(keyHash);
  }
}

export async function GET(req: Request) {
  return handleAuth(req);
}

export async function POST(req: Request) {
  return handleAuth(req);
}

async function handleAuth(req: Request) {
  const startTime = Date.now();
  const url = new URL(req.url);
  const ip = getSafeIp(req);

  // Strict rate limiting: 10 requests per 5 minutes per IP
  const limited = await rateLimit(`script-auth:${ip}`, 10, 5 * 60 * 1000);
  if (!limited.success) {
    return errorResponse("Too many requests. Try again later.", 429);
  }

  // Enforce IP reputation blocking
  const reputation = await db.ipReputation.findUnique({ where: { ip } }).catch(() => null);
  if (reputation?.blocked) {
    // Auto-unblock after 30 minutes (was 10 — stricter)
    if (reputation.lastSeenAt && Date.now() - reputation.lastSeenAt.getTime() > 30 * 60 * 1000) {
      await db.ipReputation.update({ where: { ip }, data: { blocked: false, score: 80 } }).catch(() => {});
    } else {
      return errorResponse("Access denied", 403);
    }
  }

  cleanExpiredStores();

  try {
    let parsed: ReturnType<typeof parseQuery>;

    if (req.method === "GET") {
      parsed = parseQuery(url);
    } else {
      try {
        const rawBody = await req.text();
        const body = JSON.parse(rawBody);
        parsed = {
          key: body.key || "", hwid: body.hwid || "", scriptId: body.scriptId || "",
          nonce: body.nonce || "", timestamp: body.timestamp, executor: body.executor || "Unknown",
          token: body.token || "", check: false,
        };
      } catch {
        parsed = parseQuery(url);
      }
    }

    if (!parsed.key || !parsed.hwid || !parsed.scriptId) {
      return errorResponse("Missing required fields", 400);
    }

    const { key, hwid, scriptId, executor, token, check } = parsed;
    const fingerprintHash = hashIdentifier(hwid);
    const userAgent = req.headers.get("user-agent") || "LuauEngine";
    const country = req.headers.get("cf-ipcountry") || req.headers.get("x-country") || null;

    // Replay protection: validate nonce
    if (parsed.nonce) {
      if (recentNonces.has(parsed.nonce)) {
        await recordSecurityFailure(ip, "REPLAY_NONCE_REUSED").catch(() => {});
        return errorResponse("Replay detected", 401);
      }
      // Check timestamp freshness (5 minute window)
      if (parsed.timestamp) {
        const ts = parsed.timestamp < 1e12 ? parsed.timestamp * 1000 : parsed.timestamp;
        if (Math.abs(Date.now() - ts) > 5 * 60 * 1000) {
          return errorResponse("Stale request", 401);
        }
      }
      recentNonces.set(parsed.nonce, Date.now() + 5 * 60 * 1000);
    }

    async function logAccess(success: boolean, reason: string, licenseId?: string) {
      try {
        await db.scriptAccessLog.create({
          data: { scriptId, licenseId: licenseId || null, userId: null, ip, country, success, reason, createdAt: new Date() },
        });
      } catch {}
      if (!success) {
        try { await recordSecurityFailure(ip, reason); } catch {}
      }
    }

    // Find the script
    const scriptRecord = await db.script.findUnique({
      where: { id: scriptId },
      select: { id: true, name: true, status: true, visibility: true, contentEncrypted: true, version: true, ownerId: true, getKeyLink: true, keyMode: true },
    }).catch(() => null);

    if (!scriptRecord) return errorResponse("Script not found", 404);

    if (scriptRecord.status === "DISABLED") {
      await logAccess(false, "SCRIPT_DISABLED");
      return errorResponse("Script is disabled", 403);
    }

    // Keyless mode — PUBLIC scripts don't require a license key
    if (scriptRecord.visibility === "PUBLIC") {
      await logAccess(true, "KEYLESS_ACCESS");

      void sendDiscordLog({
        event: "Script Auth — Keyless", key: "KEYLESS", scriptName: scriptRecord.name,
        ip, country, device: userAgent, hwid, success: true, timestamp: new Date().toISOString(),
      });

      let scriptPayload = decryptObject<{ key: string }>(scriptRecord.contentEncrypted).key;
      if (!isLoadStringPayload(scriptPayload)) {
        scriptPayload = obfuscateLua(scriptPayload, { strength: "maximum" });
      }
      return new NextResponse(scriptPayload, {
        headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "private, no-store" },
      });
    }

    // Per-key rate limiting: max 5 failed attempts per key per hour
    const keyHash = hashToken(key);
    const attempts = keyAttempts.get(keyHash) || { count: 0, firstAttempt: Date.now() };
    if (attempts.count >= 5 && Date.now() - attempts.firstAttempt < 3600000) {
      await logAccess(false, "KEY_RATE_LIMITED");
      await recordSecurityFailure(ip, "KEY_BRUTE_FORCE").catch(() => {});
      void sendDiscordLog({ event: "Script Auth — Brute Force Detected", key: key.slice(0, 8) + "...", scriptName: scriptRecord.name, ip, country, hwid, success: false, reason: "Key rate limited", timestamp: new Date().toISOString() });
      return errorResponse("Too many failed attempts. Try again in 1 hour.", 429);
    }

    // Runtime check: validate session token
    if (check && token) {
      const session = sessionTokens.get(token);
      if (!session || session.expires < Date.now()) {
        await logAccess(false, "INVALID_SESSION_TOKEN");
        return errorResponse("Session expired", 401);
      }
      // Verify the session matches the current request
      if (session.keyHash !== keyHash || session.hwid !== fingerprintHash) {
        await logAccess(false, "SESSION_MISMATCH");
        sessionTokens.delete(token);
        activeSessions.delete(keyHash);
        return errorResponse("Session mismatch", 401);
      }
      // Concurrent session detection: different IP using same key
      if (session.ip !== ip) {
        await logAccess(false, "CONCURRENT_SESSION");
        void sendDiscordLog({ event: "Script Auth — Concurrent Session Detected", key: key.slice(0, 8) + "...", scriptName: scriptRecord.name, ip, country, hwid, success: false, reason: "Key shared across IPs", timestamp: new Date().toISOString() });
        sessionTokens.delete(token);
        activeSessions.delete(keyHash);
        return errorResponse("Key is in use on another device", 401);
      }
      // Refresh session
      session.expires = Date.now() + 5 * 60 * 1000;
      return new NextResponse("OK", {
        headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" },
      });
    }

    // Key-based auth
    const license = await db.license.findUnique({
      where: { keyHash },
      include: { script: { include: { protectionProfile: true } }, hwids: { orderBy: { createdAt: "desc" } } },
    });

    if (!license || license.scriptId !== scriptId) {
      attempts.count++;
      keyAttempts.set(keyHash, attempts);
      await logAccess(false, "INVALID_LICENSE_OR_SCRIPT_BINDING");
      return errorResponse("Invalid license key");
    }

    if (license.script.status === "DISABLED") {
      await logAccess(false, "SCRIPT_DISABLED", license.id);
      return errorResponse("Script is disabled", 403);
    }

    // Auto-redeem UNREDEEMED keys on first use
    if (license.status === "UNREDEEMED") {
      let expiresAt: Date | null = null;
      if (license.type === "SUBSCRIPTION" && license.durationDays) {
        expiresAt = new Date(Date.now() + license.durationDays * 24 * 60 * 60 * 1000);
      }
      try {
        await db.license.update({
          where: { id: license.id },
          data: { status: "ACTIVE", redeemedAt: new Date(), redeemedBy: hwid, expiresAt },
        });
      } catch {
        return errorResponse("Failed to activate key", 500);
      }
    }

    if (license.status === "SUSPENDED") {
      attempts.count++;
      keyAttempts.set(keyHash, attempts);
      await logAccess(false, "LICENSE_SUSPENDED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Suspended", key: key.slice(0, 8) + "...", scriptName: license.script.name, ip, country, hwid, success: false, reason: "License suspended", timestamp: new Date().toISOString() });
      return errorResponse("License has been suspended", 403);
    }
    if (license.status === "BLACKLISTED") {
      attempts.count++;
      keyAttempts.set(keyHash, attempts);
      await logAccess(false, "LICENSE_BLACKLISTED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Blacklisted", key: key.slice(0, 8) + "...", scriptName: license.script.name, ip, country, hwid, success: false, reason: "License blacklisted", timestamp: new Date().toISOString() });
      return errorResponse("License is blacklisted", 403);
    }
    if (license.status === "EXPIRED" || (license.expiresAt && new Date() > license.expiresAt)) {
      if (license.status !== "EXPIRED") {
        await db.license.update({ where: { id: license.id }, data: { status: "EXPIRED" } });
      }
      await logAccess(false, "LICENSE_EXPIRED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Expired", key: key.slice(0, 8) + "...", scriptName: license.script.name, ip, country, hwid, success: false, reason: "License expired", timestamp: new Date().toISOString() });
      return errorResponse("License has expired", 403);
    }

    // HWID lock — auto-bind on first use, enforce on subsequent
    let hwidRecord = await db.hwid.findFirst({ where: { licenseId: license.id, fingerprintHash } });
    if (license.hwidLock) {
      if (!hwidRecord && license.hwids.length > 0) {
        attempts.count++;
        keyAttempts.set(keyHash, attempts);
        await logAccess(false, "HWID_MISMATCH", license.id);
        void sendDiscordLog({ event: "Script Auth — HWID Mismatch", key: key.slice(0, 8) + "...", scriptName: license.script.name, ip, country, hwid, success: false, reason: "HWID mismatch", timestamp: new Date().toISOString() });
        return errorResponse("HWID mismatch — reset from dashboard");
      }
      if (!hwidRecord) {
        hwidRecord = await db.hwid.create({
          data: { licenseId: license.id, fingerprintHash, source: "auth", lastIp: ip, lastDeviceInfo: userAgent },
        });
      } else {
        await db.hwid.update({ where: { id: hwidRecord.id }, data: { lastIp: ip, lastDeviceInfo: userAgent } });
      }
    }

    // Concurrent session detection: is this key already active from a different IP?
    const existingSession = activeSessions.get(keyHash);
    if (existingSession) {
      const session = sessionTokens.get(existingSession);
      if (session && session.expires > Date.now() && session.ip !== ip && session.hwid !== fingerprintHash) {
        await logAccess(false, "CONCURRENT_SESSION", license.id);
        void sendDiscordLog({ event: "Script Auth — Concurrent Session", key: key.slice(0, 8) + "...", scriptName: license.script.name, ip, country, hwid, success: false, reason: "Key shared across devices", timestamp: new Date().toISOString() });
        return errorResponse("Key is already in use on another device", 401);
      }
    }

    // Clear failed attempt counter on success
    keyAttempts.delete(keyHash);

    // Log the activation
    await db.activation.create({
      data: { licenseId: license.id, hwidId: hwidRecord?.id || null, fingerprintHash, ip, country, deviceInfo: userAgent, userAgent, success: true },
    }).catch(() => {});

    await logAccess(true, "AUTH_SUCCESS", license.id);

    void sendDiscordLog({
      event: "Script Authentication", key: key.slice(0, 8) + "...", scriptName: license.script.name,
      ip, country, device: userAgent, hwid, success: true, timestamp: new Date().toISOString(),
    });

    // Issue a one-time session token for runtime checks
    const sessionToken = randomToken(24);
    sessionTokens.set(sessionToken, { keyHash, ip, hwid: fingerprintHash, expires: Date.now() + 5 * 60 * 1000 });
    activeSessions.set(keyHash, sessionToken);

    let scriptPayload = decryptObject<{ key: string }>(license.script.contentEncrypted).key;
    if (!isLoadStringPayload(scriptPayload)) {
      scriptPayload = obfuscateLua(scriptPayload, { strength: "maximum" });
    }

    // Return the obfuscated source + session token
    return new NextResponse(scriptPayload + "\n--FL:" + sessionToken, {
      headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "private, no-store" },
    });
  } catch (error) {
    console.error("Auth script endpoint error:", error);
    return errorResponse("Internal server error", 500);
  }
}

import { NextResponse } from "next/server";
import type { Role } from "@prisma/client";
import { db } from "./db";
import { randomToken } from "./crypto";
import { signToken } from "./jwt";
import { getClientIp } from "./http";

export const SESSION_COOKIE_NAME = "token";
export const SESSION_TTL_MS = 7 * 24 * 60 * 60 * 1000;
export const SESSION_TTL_SECONDS = Math.floor(SESSION_TTL_MS / 1000);

export interface SessionUserCore {
  id: string;
  email: string;
  role: string;
}

export function deviceNameFromUserAgent(userAgent?: string | null) {
  if (!userAgent) return "Unknown Device";
  if (userAgent.includes("Windows")) return "Windows Device";
  if (userAgent.includes("Mac")) return "macOS Device";
  if (userAgent.includes("Linux")) return "Linux Device";
  if (userAgent.includes("Android")) return "Android Device";
  if (userAgent.includes("iPhone") || userAgent.includes("iPad")) return "iOS Device";
  return "Browser Session";
}

export async function createSessionToken(user: SessionUserCore, req: Request, options?: { deviceName?: string; expiresMs?: number }) {
  const sessionId = randomToken(24);
  const token = signToken({
    userId: user.id,
    email: user.email,
    role: user.role as Role,
    sessionId,
  });

  await db.session.create({
    data: {
      sessionToken: token,
      userId: user.id,
      userAgent: req.headers.get("user-agent"),
      ip: getClientIp(req),
      deviceName: options?.deviceName ?? deviceNameFromUserAgent(req.headers.get("user-agent")),
      expiresAt: new Date(Date.now() + (options?.expiresMs ?? SESSION_TTL_MS)),
    },
  });

  return { token, sessionId };
}

export function setSessionCookie(response: NextResponse, token: string) {
  const expires = new Date(Date.now() + SESSION_TTL_MS);
  response.cookies.set(SESSION_COOKIE_NAME, token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: SESSION_TTL_SECONDS,
    expires,
    path: "/",
  });
}

export function clearSessionCookie(response: NextResponse) {
  response.cookies.set(SESSION_COOKIE_NAME, "", {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 0,
    path: "/",
  });
}

export function clearPendingOAuthCookie(response: NextResponse) {
  response.cookies.set("pending_oauth", "", {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 0,
    path: "/",
  });
}

export async function destroySession(token: string | null | undefined) {
  if (!token) return;
  await db.session.deleteMany({ where: { sessionToken: token } }).catch(() => undefined);
}

import { db } from "./db";
import { encryptObject, generateLicenseKey, hashToken } from "./crypto";

export async function createLicenseKeys(input: {
  scriptId: string;
  ownerId: string;
  type: "LIFETIME" | "SUBSCRIPTION";
  durationDays?: number | null;
  count: number;
  note?: string | null;
  hwidLock: boolean;
  groupId?: string | null;
  tags?: string[] | null;
  trial?: boolean;
  productId?: string | null;
  transferable?: boolean;
  keyPrefix?: string | null;
}) {
  const created: string[] = [];

  for (let i = 0; i < input.count; i++) {
    let key = generateLicenseKey();
    let exists = true;
    let attempts = 0;

    while (exists && attempts < 5) {
      exists = Boolean(await db.license.findUnique({ where: { keyHash: hashToken(key) }, select: { id: true } }));
      if (exists) key = generateLicenseKey(input.keyPrefix || undefined);
      attempts += 1;
    }

    if (exists) throw new Error("Unable to generate a unique license key after several attempts");

    created.push(key);
  }

  const expiresAt =
    input.type === "SUBSCRIPTION" && input.durationDays
      ? new Date(Date.now() + input.durationDays * 24 * 60 * 60 * 1000)
      : null;

  await db.license.createMany({
    data: created.map((key) => ({
      keyEncrypted: encryptObject({ key }),
      keyHash: hashToken(key),
      type: input.type,
      status: "UNREDEEMED",
      durationDays: input.type === "SUBSCRIPTION" ? input.durationDays ?? 30 : null,
      expiresAt,
      note: input.note ?? null,
      hwidLock: input.hwidLock,
      groupId: input.groupId || null,
      tags: input.tags || undefined,
      trial: input.trial ?? false,
      productId: input.productId || undefined,
      transferable: input.transferable ?? true,
      scriptId: input.scriptId,
      ownerId: input.ownerId,
    })),
  });

  return created;
}

import { NextResponse } from "next/server";

// This endpoint serves the cached obfuscated loader payload
// The public loader endpoint returns only a tiny bootstrap that fetches this
// Bots only see the bootstrap, not the actual code

declare global {
  var loaderCache: Map<string, { code: string; expires: number }>;
}

export async function GET(
  req: Request,
  { params }: { params: Promise<{ cacheKey: string }> },
) {
  const { cacheKey } = await params;

  // Try the global cache first (set by the loader route)
  const cache = (globalThis as any).loaderCache || global.loaderCache;
  if (!cache) {
    return new NextResponse("ERROR: Cache not available", {
      headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" },
    });
  }

  const entry = cache.get(cacheKey);
  if (!entry || entry.expires < Date.now()) {
    return new NextResponse("ERROR: Expired", {
      headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" },
    });
  }

  // Delete after read (one-time use)
  cache.delete(cacheKey);

  return new NextResponse(entry.code, {
    headers: {
      "Content-Type": "text/plain; charset=utf-8",
      "Cache-Control": "no-store, no-cache, must-revalidate",
      "Access-Control-Allow-Origin": "*",
    },
  });
}

import { NextResponse } from "next/server";
import { obfuscateLua } from "@/lib/obfuscator";
import { getAuthenticatedUser, rateLimit } from "@/lib/http";
import { z } from "zod";

