import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { rateLimit } from "@/lib/rate-limit";
import { getRateLimitHeaders } from "@/lib/rate-limit";
import { decryptObject, hashString, hashToken, randomToken } from "@/lib/crypto";
import { obfuscateLua, isLoadStringPayload } from "@/lib/obfuscator";
import { getClientIp, hashIdentifier } from "@/lib/http";
import { recordSecurityFailure } from "@/lib/ip-reputation";
import { sendDiscordLog } from "@/lib/discord-logger";

// In-memory stores (cleared on restart)
const sessionTokens = new Map<string, { keyHash: string; ip: string; hwid: string; expires: number }>();
const keyAttempts = new Map<string, { count: number; firstAttempt: number }>();
const recentNonces = new Map<string, number>();
const activeSessions = new Map<string, string>(); // keyHash -> sessionId

function errorResponse(message: string, status = 401) {
  return new NextResponse(`ERROR: ${message}`, {
    status,
    headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" },
  });
}

function parseQuery(url: URL) {
  return {
    key: url.searchParams.get("key") || "",
    hwid: url.searchParams.get("hwid") || "",
    scriptId: url.searchParams.get("scriptId") || "",
    nonce: url.searchParams.get("nonce") || "",
    timestamp: url.searchParams.get("ts") ? Number(url.searchParams.get("ts")) : undefined,
    executor: url.searchParams.get("executor") || "Unknown",
    token: url.searchParams.get("token") || "",
    check: url.searchParams.get("check") === "1",
  };
}

function getSafeIp(req: Request): string {
  // Only trust the FIRST IP in X-Forwarded-For (closest proxy)
  // Railway sets this correctly — don't trust client-supplied spoofing
  const xff = req.headers.get("x-forwarded-for") || "";
  const first = xff.split(",")[0]?.trim();
  if (first && /^\d+\.\d+\.\d+\.\d+$/.test(first)) return first;
  return req.headers.get("x-real-ip") || "unknown";
}

function cleanExpiredStores() {
  const now = Date.now();
  // Session tokens expire after 5 minutes
  for (const [token, data] of sessionTokens) {
    if (data.expires < now) sessionTokens.delete(token);
  }
  // Key attempts reset after 1 hour
  for (const [key, data] of keyAttempts) {
    if (now - data.firstAttempt > 3600000) keyAttempts.delete(key);
  }
  // Nonces expire after 5 minutes
  for (const [nonce, expires] of recentNonces) {
    if (expires < now) recentNonces.delete(nonce);
  }
  // Active sessions expire after 2 minutes (if no runtime check)
  for (const [keyHash, sessionId] of activeSessions) {
    const session = sessionTokens.get(sessionId);
    if (!session || session.expires < now) activeSessions.delete(keyHash);
  }
}

export async function GET(req: Request) {
  return handleAuth(req);
}

export async function POST(req: Request) {
  return handleAuth(req);
}

async function handleAuth(req: Request) {
  const startTime = Date.now();
  const url = new URL(req.url);
  const ip = getSafeIp(req);

  // Strict rate limiting: 10 requests per 5 minutes per IP
  const limited = await rateLimit(`script-auth:${ip}`, 10, 5 * 60 * 1000);
  if (!limited.success) {
    return errorResponse("Too many requests. Try again later.", 429);
  }

  // Enforce IP reputation blocking
  const reputation = await db.ipReputation.findUnique({ where: { ip } }).catch(() => null);
  if (reputation?.blocked) {
    // Auto-unblock after 30 minutes (was 10 — stricter)
    if (reputation.lastSeenAt && Date.now() - reputation.lastSeenAt.getTime() > 30 * 60 * 1000) {
      await db.ipReputation.update({ where: { ip }, data: { blocked: false, score: 80 } }).catch(() => {});
    } else {
      return errorResponse("Access denied", 403);
    }
  }

  cleanExpiredStores();

  try {
    let parsed: ReturnType<typeof parseQuery>;

    if (req.method === "GET") {
      parsed = parseQuery(url);
    } else {
      try {
        const rawBody = await req.text();
        const body = JSON.parse(rawBody);
        parsed = {
          key: body.key || "", hwid: body.hwid || "", scriptId: body.scriptId || "",
          nonce: body.nonce || "", timestamp: body.timestamp, executor: body.executor || "Unknown",
          token: body.token || "", check: false,
        };
      } catch {
        parsed = parseQuery(url);
      }
    }

    if (!parsed.key || !parsed.hwid || !parsed.scriptId) {
      return errorResponse("Missing required fields", 400);
    }

    const { key, hwid, scriptId, executor, token, check } = parsed;
    const fingerprintHash = hashIdentifier(hwid);
    const userAgent = req.headers.get("user-agent") || "LuauEngine";
    const country = req.headers.get("cf-ipcountry") || req.headers.get("x-country") || null;

